     1→"use client";
     2→
     3→import { useEffect, useState, useMemo } from "react";
     4→import { useRouter } from "next/navigation";
     5→import { Archive } from "lucide-react";
     6→import { SiteHeader } from "@/components/layout/site-header";
     7→import { ProCard } from "@/components/workspace/pro-card";
     8→import { FloatingDock } from "@/components/workspace/floating-dock";
     9→import { ProjectDetailOverlay } from "@/components/workspace/project-detail-overlay";
    10→import { useAuth } from "@/providers/auth-provider";
    11→import { useProfile } from "@/hooks/use-profile";
    12→import { useLanguageStore } from "@/store/language-store";
    13→import { cn } from "@/lib/utils";
    14→
    15→interface Project {
    16→    id: string;
    17→    title?: string;
    18→    text: string;
    19→    description?: string;
    20→    color?: string;
    21→    globalScore?: number;
    22→    recommendation?: string;
    23→    confidenceLevel?: string;
    24→    viabilityScore?: number;
    25→    classification?: string;
    26→    timestamp: string;
    27→    isDemo?: boolean;
    28→    isArchived?: boolean;
    29→    analysis?: any;
    30→}
    31→
    32→function getProjectDecision(p: Project): string {
    33→    return p.recommendation ?? p.classification ?? "DRAFT";
    34→}
    35→
    36→function getProjectTitle(p: Project): string {
    37→    return p.title ?? p.text;
    38→}
    39→
    40→export default function WorkspacePage() {
